void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("Captain1_4", LinkRandPhrase(						StringFromKey("Captain1_1"),						StringFromKey("Captain1_2"),						StringFromKey("Captain1_3")));			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "first time";		break;		case "":			dialog.text = "";			link.l1 = "";			link.l1.go = "";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}